import React, { useState } from 'react';
import SlidingLogin from './components/SlidingLogin';

export default function App() {
  const [user, setUser] = useState(null);

  if (!user) {
    return <SlidingLogin onLogin={setUser} />;
  }

  return (
    <div style={{ 
      background: '#05091a', 
      minHeight: '100vh', 
      color: 'white', 
      padding: 40, 
      textAlign: 'center' 
    }}>
      <h1>✅ App cargando correctamente</h1>
      <p>Bienvenido: {user.nombre}</p>
      <button onClick={() => setUser(null)} style={{padding: '10px 20px', marginTop: '20px'}}>
        Cerrar sesión
      </button>
    </div>
  );
}
